from flask import Flask, redirect, request, url_for, jsonify
import urllib.parse

app = Flask(__name__)

# Configuration
CLIENT_ID = 'your-client-id'
AUTHORIZATION_ENDPOINT = 'https://your-identity-provider.com/authorize'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/')
def home():
    return '<h1>Welcome to the Internal Admin Dashboard</h1><a href="/login">Login</a>'

@app.route('/login')
def login():
    params = {
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'scope': 'openid',
        'response_type': 'id_token'
    }
    url = AUTHORIZATION_ENDPOINT + '?' + urllib.parse.urlencode(params)
    return redirect(url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if not id_token:
        return 'Error: id_token not found in callback parameters.', 400
    # In a real implementation, you would validate the id_token here.
    return jsonify({'message': 'Successfully authenticated', 'id_token': id_token})

if __name__ == '__main__':
    app.run(debug=True)